class SqlQueryValidator {
  private val allowedColumns = Set(
    "user_id", "username", "email", "created_at", "updated_at",
    "order_id", "product_id", "quantity", "price", "total",
    "transaction_date", "status", "category", "region", "country"
  )

  private val allowedTables = Set(
    "users", "orders", "products", "transactions", "customers"
  )

  private val allowedOperators = Set(
    "=", "!=", "<>", ">", "<", ">=", "<=", "LIKE", "IN", "NOT IN",
    "IS NULL", "IS NOT NULL", "BETWEEN", "AND", "OR"
  )

  private val allowedAggregations = Set(
    "COUNT", "SUM", "AVG", "MIN", "MAX", "STDDEV", "VARIANCE"
  )

  private val allowedFunctions = Set(
    "UPPER", "LOWER", "TRIM", "SUBSTRING", "CONCAT",
    "YEAR", "MONTH", "DAY", "DATE", "TIMESTAMP",
    "CAST", "COALESCE", "NULLIF"
  )

  private val dangerousPatterns = List(
    Pattern.compile(".*;.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\b(DROP|DELETE|INSERT|UPDATE|CREATE|ALTER|TRUNCATE|EXEC|EXECUTE)\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*--.*"),
    Pattern.compile(".*/\\*.*\\*/.*"),
    Pattern.compile(".*\\bUNION\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bINTO\\s+OUTFILE\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bLOAD_FILE\\b.*", Pattern.CASE_INSENSITIVE),
    Pattern.compile(".*\\bxp_cmdshell\\b.*", Pattern.CASE_INSENSITIVE)
  )

  def validateQuery(query: String): Either[String, Unit] = {
    val normalizedQuery = query.trim

    if (normalizedQuery.isEmpty) {
      return Left("Query cannot be empty")
    }

    for (pattern <- dangerousPatterns) {
      if (pattern.matcher(normalizedQuery).matches()) {
        return Left(s"Query contains dangerous pattern: ${pattern.pattern()}")
      }
    }

    if (!normalizedQuery.toUpperCase.startsWith("SELECT")) {
      return Left("Only SELECT queries are allowed")
    }

    Right(())
  }

  def validateColumnName(column: String): Boolean = {
    allowedColumns.contains(column.toLowerCase)
  }

  def validateTableName(table: String): Boolean = {
    allowedTables.contains(table.toLowerCase)
  }

  def validateOperator(operator: String): Boolean = {
    allowedOperators.contains(operator.toUpperCase)
  }

  def validateFunction(function: String): Boolean = {
    val funcName = function.toUpperCase
    allowedAggregations.contains(funcName) || allowedFunctions.contains(funcName)
  }
}

class ParameterizedQueryBuilder {
  def buildQuery(template: String, parameters: Map[String, Any]): String = {
    var query = template
    parameters.foreach { case (key, value) =>
      val placeholder = s":$key"
      val sanitizedValue = sanitizeParameter(value)
      query = query.replace(placeholder, sanitizedValue)
    }
    query
  }

  private def sanitizeParameter(value: Any): String = {
    value match {
      case s: String => s"'${escapeString(s)}'"
      case i: Int => i.toString
      case l: Long => l.toString
      case d: Double => d.toString
      case f: Float => f.toString
      case b: Boolean => b.toString
      case null => "NULL"
      case seq: Seq[_] => seq.map(sanitizeParameter).mkString("(", ",", ")")
      case _ => s"'${escapeString(value.toString)}'"
    }
  }

  private def escapeString(s: String): String = {
    s.replace("'", "''")
      .replace("\\", "\\\\")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
  }
}

class SecureQueryExecutor(spark: SparkSession) {
  private val validator = new SqlQueryValidator()
  private val queryBuilder = new ParameterizedQueryBuilder()

  def executeQuery(request: QueryRequest): QueryResponse = {
    validator.validateQuery(request.query) match {
      case Left(error) =>
        QueryResponse(success = false, error = Some(s"Validation failed: $error"))
      
      case Right(_) =>
        Try {
          val finalQuery = if (request.parameters.nonEmpty) {
            queryBuilder.buildQuery(request.query, request.parameters)
          } else {
            request.query
          }

          val df = spark.sql(finalQuery)
          val rowCount = df.count()
          
          val limit = 10000
          val limitedDf = df.limit(limit)
          
          val data = limitedDf.collect().map { row =>
            row.schema.fieldNames.map { fieldName =>
              fieldName -> Option(row.getAs[Any](fieldName)).getOrElse(null)
            }.toMap
          }.toSeq

          QueryResponse(
            success = true,
            data = Some(data),
            rowCount = Some(rowCount)
          )
        } match {
          case Success(response) => response
          case Failure(exception) =>
            QueryResponse(
              success = false,
              error = Some(s"Query execution failed: ${exception.getMessage}")
            )
        }
    }
  }

  def executeQueryWithTimeout(request: QueryRequest, timeoutSeconds: Int = 300): QueryResponse = {
    import scala.concurrent._
    import scala.concurrent.duration._
    import ExecutionContext.Implicits.global

    val future = Future {
      executeQuery(request)
    }

    Try(Await.result(future, timeoutSeconds.seconds)) match {
      case Success(response) => response
      case Failure(_: TimeoutException) =>
        QueryResponse(success = false, error = Some(s"Query execution timeout after $timeoutSeconds seconds"))
      case Failure(exception) =>
        QueryResponse(success = false, error = Some(s"Query execution error: ${exception.getMessage}"))
    }
  }
}

