    "SELECT product_id, category, SUM(quantity) as total_quantity FROM orders WHERE category = :category GROUP BY product_id, category ORDER BY total_quantity DESC LIMIT :limit"
  }

  def getRevenueByRegion(): String = {
    "SELECT region, SUM(total) as revenue FROM orders GROUP BY region ORDER BY revenue DESC"
  }

  def getUserOrderSummary(): String = {
    "SELECT u.user_id, u.username, COUNT(o.order_id) as order_count, SUM(o.total) as total_spent FROM users u LEFT JOIN orders o ON u.user_id = o.user_id WHERE u.user_id = :user_id GROUP BY u.user_id, u.username"
  }

  def validateTemplate(templateName: String, parameters: Map[String, Any]): Either[String, String] = {
