      case "users_by_region" => getUsersByRegion()
      case "orders_by_date_range" => getOrdersByDateRange()
      case "top_products_by_category" => getTopProductsByCategory()
      case "revenue_by_region" => getRevenueByRegion()
      case "user_order_summary" => getUserOrderSummary()
      case _ => return Left(s"Unknown template: $templateName")
